"""Auto-generated by eval/iterate.py.

Hypothesis: MISSING answers cluster on specific models (Kimi-K2.6, Qwen3-VL) suggesting they truncate or skip output. Forcing an explicit per-section walkthrough with concrete CA DL forensic anchors will both eliminate skips and improve format-check accuracy on S5/S6/S7/S8.
Targets:    S5 :: YES → MISSING, S6 :: YES → MISSING, S7 :: YES → MISSING, S8 :: YES → MISSING, S13 :: YES → MISSING, S1 :: YES → NO
"""

from __future__ import annotations

NAME = 'v4_section_by_section_scaffold'

SYSTEM = 'You are an expert document forensics examiner specialising in California Driver License / ID cards.\n\nPROCESS:\n1. Read the hint page checklist. Count the total number of check IDs.\n2. Work through EVERY section in order, answering EVERY check ID. Do not skip any.\n3. Before returning, verify your JSON contains exactly one entry per check ID from the checklist.\n\nOMISSIONS ARE FAILURES. An omitted check scores worse than a wrong answer. If unsure, answer UNVERIFIABLE — never leave it out.\n\nAnswer values (exactly one per check):\n- YES — confirmed present/correct as described\n- NO — confirmed absent/wrong/anomalous\n- WARN — visible but borderline/suspicious\n- UNVERIFIABLE — image quality, missing side, modality limit, or precondition N/A\n- CONTEXT — descriptive/generational\n\nWARN vs UNVERIFIABLE: WARN means you saw it and something looks off. UNVERIFIABLE means you cannot perform the test (resolution, modality, missing side, N/A precondition).\n\nBe independent and rigorous; do not presume genuineness or forgery.\n\nReturn ONLY valid JSON, no fences, no preamble, one entry per check ID.'

GUIDANCE = 'California DL/ID forensic anchors (use these as ground truth when answering format checks):\n\n[S5 Name field]\n- Last name on its own line preceded by \'LN\' label\n- First+middle on next line preceded by \'FN\' label\n- ALL CAPS, sans-serif\n- Truncation with no terminator if name exceeds field width\n\n[S6 License number]\n- Exactly 1 letter followed by 7 digits (e.g., D1234567)\n- Printed in red/maroon on Gen 3+; label \'DL\'\n- Located upper-right area below header\n\n[S7 Date fields]\n- Format MM/DD/YYYY (4-digit year)\n- DOB, ISS (issue), EXP (expiration) all present\n- EXP typically = DOB month/day + 5 or 8 years from ISS\n- For under-21: EXP often on 21st birthday\n- ISS ≤ today ≤ EXP for a valid card\n\n[S8 Physical descriptors]\n- SEX: M or F (single letter)\n- HGT: format like 5\'-10"\n- WGT: numeric lb (e.g., 150 lb)\n- EYES: 3-letter code (BRN, BLU, HZL, GRN, BLK, GRY)\n- HAIR: 3-letter code (BRN, BLK, BLN, RED, GRY, BAL)\n\n[S9 Under-21]\n- Card oriented vertically (portrait) for under-21 issued cards\n- Red \'AGE 21 IN YYYY\' banner\n- If subject is clearly 21+, these checks are UNVERIFIABLE (precondition N/A)\n\n[S13 Back DD field & barcodes]\n- PDF417 2D barcode (mandatory, AAMVA standard)\n- 1D Code 39 above magstripe (legacy, may be absent on newer Gen)\n- DD field = document discriminator, alphanumeric, typically 10 chars\n- Gen 4 adds a second 2D barcode for digital signature; Gen 3 does NOT have this — absence on a Gen 3 card is NOT a red flag\n\n[S14 Barcode cross-field]\n- Requires actually decoding the PDF417. If you cannot decode the barcode payload from the image, answer UNVERIFIABLE for all S14 checks. Do NOT infer barcode contents from visible front-side text.\n\n[S1 Generation]\n- Gen 3 (2010–2021): single PDF417, bear hologram, no tactile DOB\n- Gen 4 (2022+): adds gold bear+star REAL ID marker variations, second 2D barcode, raised tactile DOB\n- If card is Gen 3, Gen 4-specific checks are UNVERIFIABLE (precondition N/A), not NO.'


def build_user_text(*, page: dict, guidance: str | None, image_count: int) -> str:
    g = guidance if guidance is not None else GUIDANCE
    checklist = "\n\n".join(
        f"[{s['id']}] {s['title']}\n"
        + "\n".join(
            f"  {h[0]}: {h[1]}" + (f" [{h[2]}]" if h[2] else "")
            for h in s["hints"]
        )
        for s in page["sections"]
    )
    img_list = ", ".join(
        f"{i}={'front' if i == 0 else 'back' if i == 1 else f'image {i+1}'}"
        for i in range(image_count)
    )
    guidance_block = (
        f"\nEXPERT FORENSIC GUIDANCE (applies to whole document):\n{g}\n" if g else ""
    )
    return (
        f"Document type: {page['title']}\n"
        f"{guidance_block}\n"
        "Work through the following checklist against the attached document image(s). "
        "Provide a 1-sentence finding per check.\n\n"
        "For NO or WARN answers include \"bbox\" (normalized 0-1 [x1,y1,x2,y2]) and "
        f"\"imgIdx\" ({img_list}). Omit both otherwise.\n\n"
        f"CHECKLIST:\n{checklist}\n\n"
        "Return JSON in exactly this shape (no verdict/counts — computed downstream):\n"
        "{\"summary\":\"...\",\"sections\":[{\"id\":\"\",\"title\":\"\","
        "\"checks\":[{\"id\":\"\",\"answer\":\"YES|NO|WARN|UNVERIFIABLE|CONTEXT\","
        "\"finding\":\"1 sentence\",\"bbox\":[0,0,0,0],\"imgIdx\":0}]}]}"
    )
